function improveVocabulary(text: string): string {
  let improved = text

  const vocabReplacements: [RegExp, string][] = [
    /\bgood\b/gi, 'beneficial',
    /\bbad\b/gi, 'detrimental',
    /\bbig\b/gi, 'significant',
    /\bsmall\b/gi, 'minor',
    /\bvery\b/gi, '',
    /\breally\b/gi, '',
    /\ba lot\b/gi, 'significantly',
    /\bpeople\b/gi, 'individuals',
    /\bthings?\b/gi, 'aspects',
    /\bstuff\b/gi, 'matters',
    /\bhave to\b/gi, 'must',
    /\bneed to\b/gi, 'must',
    /\bshow\b/gi, 'demonstrate',
    /\bget\b/gi, 'obtain',
    /\buse\b/gi, 'utilize',
    /\btell\b/gi, 'indicate',
    /\bsay\b/gi, 'state',
    /\bso\b/gi, 'therefore',
    /\bbecause\b/gi, 'as',
    /\bbut\b/gi, 'however',
    /\balso\b/gi, 'furthermore',
  ]

  for (let i = 0; i < vocabReplacements.length; i += 2) {
    const pattern = vocabReplacements[i]
    const replacement = vocabReplacements[i + 1] as string
    if (replacement) {
      improved = improved.replace(pattern, replacement)
    } else {
      improved = improved.replace(pattern, '')
    }
  }

  improved = improved.replace(/\s{2,}/g, ' ').trim()

  return improved
}

function improveComplexity(text: string): string {
  let improved = text

  const simpleSentences = text.split(/[.!?]+\s*/).filter(s => s.trim().length > 0 && s.split(/\s+/).length < 10)
  if (simpleSentences.length > 0) {
    improved = improved.replace(
      /\b(I think|In my opinion|From my perspective)\b/gi,
      'It could be argued that',
    )
  }

  if (!/\bwhich\b/i.test(text) && !/\bthat\b/i.test(text)) {
    improved = improved.replace(
      /^(\w[^.]*?)(\.)/m,
      '$1, which is an important factor to consider.$2',
    )
  }

  return improved
}

